{
  "summary": "The paper proposes incorporating structural locality features into non-parametric language models by learning simple linear transformations of retrieval distances based on hierarchical locality levels. Evaluated on Java source code and Wikipedia text, this approach improves retrieval quality and language modeling performance, demonstrating the benefit of explicitly modeling locality beyond contextual similarity.",
  "strengths": [
    {
      "point": "Addresses an important limitation of existing kNN-LMs by incorporating structural locality features to improve retrieval.",
      "evidence": "The paper shows that traditional contextual similarity metrics do not fully capture locality, motivating explicit locality features that improve perplexity and token accuracy on two diverse domains."
    },
    {
      "point": "Proposes a simple, parameter-efficient method that can be applied without retraining the underlying parametric LM.",
      "evidence": "Only a small number of linear transformation parameters per locality level are learned on a validation set, making the approach lightweight and easy to integrate."
    },
    {
      "point": "Empirically validated on large-scale datasets from both natural language (Wikipedia) and programming language (Java) domains.",
      "evidence": "Experiments demonstrate consistent improvements in perplexity and token prediction accuracy, with detailed analysis of locality effects and qualitative examples."
    }
  ],
  "weaknesses": [
    {
      "point": "Lacks comparison to prior learned metric learning approaches for retrieval.",
      "evidence": "No discussion or experiments comparing the proposed linear transformations to more flexible learned metrics such as Mahalanobis distances or neural similarity functions."
    },
    {
      "point": "Methodological choices are insufficiently justified and explored.",
      "evidence": "The paper does not ablate or justify the use of only linear transformations, nor does it analyze the impact of the number or granularity of locality levels."
    },
    {
      "point": "Evaluation is limited in scope and depth.",
      "evidence": "No stronger baselines incorporating structural or metadata features are compared; retrieval quality metrics like precision@k or recall@k are missing; and no statistical significance testing is reported."
    },
    {
      "point": "Reproducibility is hindered by missing details.",
      "evidence": "The paper omits specifics on validation set size and parameter learning procedures, does not provide code or hyperparameter details for the underlying models and retrieval."
    },
    {
      "point": "Clarity issues regarding locality feature definitions and extraction.",
      "evidence": "Ambiguities exist in how mutually exclusive locality levels are defined and handled, especially for overlapping hierarchical features; extraction details for Wikipedia locality features are insufficient."
    },
    {
      "point": "No discussion of scalability or generalization limitations.",
      "evidence": "The computational overhead of applying locality-based distance modifications at large scale is not addressed; potential overfitting to specific hierarchies and robustness to weak locality are unexplored."
    },
    {
      "point": "Limited domain coverage and no cross-domain transfer experiments.",
      "evidence": "Validation is restricted to Java and Wikipedia, with no experiments or discussion on applicability to other languages, domains, or hierarchical structures."
    },
    {
      "point": "Overlooks related work on metadata-enhanced retrieval in language models.",
      "evidence": "Prior work incorporating document identifiers or topic tags into retrieval-augmented LMs is not cited or compared."
    }
  ],
  "questions": [
    {
      "question": "How would the proposed approach compare to more flexible learned metric learning methods for retrieval?",
      "motivation": "Understanding this would clarify the novelty and effectiveness of the simple linear transformations relative to existing metric learning techniques."
    },
    {
      "question": "How sensitive are results to the choice and granularity of locality levels, and could nonlinear transformations improve performance?",
      "motivation": "Exploring these factors could reveal whether the current design is optimal or if more expressive models could yield further gains."
    },
    {
      "question": "What is the computational overhead and scalability of applying locality-based distance modifications in very large datastores?",
      "motivation": "Practical deployment requires understanding efficiency and feasibility at scale."
    },
    {
      "question": "How well does the method generalize to domains with different or weaker locality structures?",
      "motivation": "Assessing robustness and transferability is important for broader applicability."
    },
    {
      "question": "Can the authors provide code, hyperparameters, and detailed training procedures to facilitate reproducibility?",
      "motivation": "Transparency and reproducibility are critical for adoption and validation by the community."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
